import{_ as a,o as t,c as p,j as r,a as b,a1 as n}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"生之欲","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/1.血统与训练/4.综合类/千禧骑士/武器/生之欲.md","filePath":"4.资源分区/1.血统与训练/4.综合类/千禧骑士/武器/生之欲.md"}'),s={name:"4.资源分区/1.血统与训练/4.综合类/千禧骑士/武器/生之欲.md"};function o(d,e,l,_,i,c){return t(),p("div",null,[...e[0]||(e[0]=[r("h1",{id:"生之欲",tabindex:"-1"},[b("生之欲 "),r("a",{class:"header-anchor",href:"#生之欲","aria-label":'Permalink to "生之欲"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"灵魂蓝调015")])])],-1),n('<h1 id="生之欲-1" tabindex="-1">生之欲 <a class="header-anchor" href="#生之欲-1" aria-label="Permalink to &quot;生之欲&quot;">​</a></h1><p>生之欲<br> D+500<br> 特异本质<br> “你来！”我就观看，见有一匹灰色马。骑在马上的，名字叫做死，阴府也随着他，有权柄赐给他们，可以用刀剑、饥荒、瘟疫、野兽，杀害地上四分之一的人。</p><p>这是一柄7L武器伤害，重型武器，具有威猛2的锈绿色巨镰，其镰刃锋利，镰柄上自上而下刻着战争、饥荒、瘟疫、野兽的图像。使用生之欲的前提为信仰【雅威】或成为千禧骑士。</p><p>生之欲无需主动升级，只需购买对应数量的刻印就会自动升级，同时，每记刻印都不会提供属性点，并在升至对应等级时获得注明的武器伤害。<br> 升级至C级需要至少1个刻印，并重置所需刻印数，升级到C级提升5L武器伤害；升级至B级至少需要在升级至C级后再获得2个刻印，升级到B级提升7L武器伤害；升级至A级至少需要在升级至B级后再获得4个刻印，升级到A级提升9L武器伤害和2点附加成功。</p><p>在此阶段下，获得终末之始、天启阵列两个特性。<br> 终末之始：<br> 镰刀挥舞，鲜花盛开。<br> 被生之欲杀死的敌人的尸体会迅速长满鲜花，然后在几息内，鲜花将吸取养分，并将遗体彻底损毁。无论敌人是何种类型的敌人，都会被终末之始所影响。这是一个B级祝福来源的免疫复活效果。</p><p>天启阵列：<br> 当持有者使用生之欲造成异常点数使某一敌人达到毁灭状态时，可以选择不令其正常进入毁灭状态，而是将其永久转化为天启的先锋，你可以以语言命令他们行事，即使你的要求会让他们失去生命或者更加珍贵的东西。</p><p>刻印<br> 每个刻印的价格都是D+500，购买时无需按顺序购买。</p><p>第一刻印：天启<br> 现在，持有者使用生之欲进行攻击时，可以选择将攻击出目转化为等量的精神束缚点数，正常使用意志豁免进行标准豁免，但前提是被攻击的目标生命中最好状态不存在任何完好。</p><p>第二刻印：揭印<br> 现在，持有者使用生之欲每杀死过同等级敌人的那场影片结束后，就会获得1点武器伤害，每以此法获得2点武器伤害，就再获得1点武器伤害。</p><p>第三刻印：征服<br> 现在，持有者使用生之欲进行攻击时，被成功命中且造成伤害的敌人还会受到仅生效一轮的，等同于千禧骑士武器选择的属性附加*2点的防御减值，自行选择减少的防御类型。</p><p>第四刻印：瘟疫<br> 现在，持有者使用生之欲进行攻击时，被成功命中且造成伤害的敌人还会受到仅生效一轮的，等同于千禧骑士武器选择的属性附加*2点的攻击检定减值。</p><p>第五刻印：饥荒<br> 现在，持有者使用生之欲进行攻击时，攻击者的触及范围额外提升持有者风度上的附加成功*1米。</p><p>第六刻印：野兽<br> 每轮一次，持有者使用生之欲杀死一名同等级的敌人时，还会从其的尸骸上召唤一具听从持有者指挥的天启仆从。每轮至多以此法制造一具天启仆从。<br> 天启仆从的数据如下：<br> 力量5 敏捷5 智力3 感知3 沉着3 其他属性全1<br> 武技3 运动3 其他技能均为1级<br> 天生武器3 攀爬3 三豁免1 侦查1 追踪1<br> 天启仆从受到攻击时，只要这次攻击成功造成了伤害，天启仆从就会立即死亡。天启仆从的天生武器攻击会正常造成严重伤害，初始具有3L天生武器伤害。<br> 在获得第六刻印后，持有者可以向第六刻印中投入更多XP以提升制造出的天启仆从的数据。天启仆从不能获得任何强化，也无法执行任何除攻击外的指令。<br> 3XP：天启仆从将正常计算自身血量，不再受到任何伤害时就立刻死亡。<br> 3XP：天启仆从将提升1级技能（购买时选择）、1级属性（购买时选择）、1级专业。<br> 天启仆从的属性等级上限遵循正常属性规则，视为已经具有了D级强化。技能等级上限受生之欲的支线等级影响，视为与生之欲支线等级同级。</p><p>第七刻印：死亡<br> 生之欲的【终末之始】提供的免疫复活能力将上升至A级。</p><p>第八刻印：终末<br> 这一刻印可以购买两次，每次购买选择一项未选择过的选项。<br> ①在影片中，每存在一名存活的天启先锋，生之欲的持有者就会获得1点攻击检定上的亵渎加值。<br> ②在影片中，每存在三名存活的天启仆从，生之欲的持有者就会获得1点偏斜防御。</p><hr><p>Copyright ? 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',17)])])}const m=a(s,[["render",o]]);export{f as __pageData,m as default};
